INSERT INTO public.photos VALUES (23977, 'Pl. de la Constituciâ”śâ”‚n 1904', '23 de octubre de 1904. Inauguraciâ”śâ”‚n del Monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y de la Patria en la plaza de la Constituciâ”śâ”‚n. El castillo que se levanta detrâ”śĂ­s es una construcciâ”śâ”‚n efâ”śÂˇmera proyectada por Ricardo Magdalena, que cubre la Fuente de Neptuno. Inicialmente prevista su igniciâ”śâ”‚n en las fiestas del Pilar, â”śÂ®sta no se llevâ”śâ”‚ a cabo y acabâ”śâ”‚ desmantelâ”śĂ­ndose el 25 de octubre. Fuente visual: Estudio Coyne, AHPZ', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65205900, -0.88097800, '0101000020E61000000ADB4FC6F830ECBFFF0758AB76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259514858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259514858.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259514858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23985, 'Pl. de la Constituciâ”śâ”‚n 1902', 'Fiestas del Pilar de 1902. La plaza de la Constituciâ”śâ”‚n luce engalanada el dâ”śÂˇa 10 de octubre, fecha de la inauguraciâ”śâ”‚n al pâ”śâ•‘blico de la lâ”śÂˇnea elâ”śÂ®ctrica del tranvâ”śÂˇa que conectaba con la playa de Torrero. El dâ”śÂˇa antes los vehâ”śÂˇculos habâ”śÂˇan sido ritualmente bendecidos por el arzobispo Soldevila. En primer tâ”śÂ®rmino, la jardinera nâ”¬â•‘ 41, traccionada por caballerâ”śÂˇas. En el centro de la imagen, tranvâ”śÂˇa elâ”śÂ®ctrico prestado para la ocasiâ”śâ”‚n por la ciudad de San Sebastiâ”śĂ­n, tirando de un remolque cerrado hasta entonces tirado por caballerâ”śÂˇas.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65181200, -0.88118800, '0101000020E6100000B115342DB132ECBFF7915B936ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15496845845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15496845845.webp', 'https://www.flickr.com/photos/zaragozaantigua/15496845845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23998, 'Cine Farrusini 1907', 'Aunque la barraca ambulante del seâ”śâ–’or Farrusini, con su cinematâ”śâ”‚grafo, recorrâ”śÂˇa las ciudades espaâ”śâ–’olas, hacia 1907 se quedâ”śâ”‚ en Zaragoza, aprovechando la inminente celebraciâ”śâ”‚n del centenario de los Sitios. En la imagen, fachada del espectâ”śĂ­culo, sin que se pueda determinar si su instalaciâ”śâ”‚n es en la calle de San Miguel 5, futuros locales de Criado y Lorenzo y del cine Goya. Luis Buâ”śâ–’uel relatâ”śâ”‚ que su primera experiencia cinematogrâ”śĂ­fica como espectador se dio en este lugar. Fuente visual: AMZ', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65106800, -0.88053800, '0101000020E6100000F4531C075E2DECBF6FBC3B3256D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21165699386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21165699386.webp', 'https://www.flickr.com/photos/zaragozaantigua/21165699386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23999, 'Pl. de la Constituciâ”śâ”‚n 1931', 'Foto: Marâ”śÂˇn Chivite. Martes 14 de abril de 1931. Celebraciâ”śâ”‚n de la proclamaciâ”śâ”‚n de la II Repâ”śâ•‘blica, en la plaza de la Constituciâ”śâ”‚n de Zaragoza. Al fondo, el inicio del paseo de la Independencia, del que proviene la manifestaciâ”śâ”‚n popular con banderas republicanas. Fuente: Archivo Heraldo de Aragâ”śâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65187100, -0.88099800, '0101000020E6100000D0ECBAB72231ECBFFC1A498270D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21251056479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21251056479.webp', 'https://www.flickr.com/photos/zaragozaantigua/21251056479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24011, 'Plaza Espaâ”śâ–’a 2001', 'El 30 de junio de 2001, el equipo de fâ”śâ•‘tbol local resultâ”śâ”‚ vencedor en la Copa del Rey, un campeonato de carâ”śĂ­cter nacional. Esa noche, miles de seguidores del Real Zaragoza se acercaron a la plaza de Espaâ”śâ–’a para celebrarlo en el Monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y de la Patria. En la foto, detalle de la concentraciâ”śâ”‚n cavernâ”śÂˇcola. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24025835073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24025835073.webp', 'https://www.flickr.com/photos/zaragozaantigua/24025835073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24022, 'Plaza de Espaâ”śâ–’a 1958', '"Que por una noche seamos todos hermanos, que por una noche los duros de corazâ”śâ”‚n sean generosos, que por una noche cenen los pobresĂ”Ă‡ÂŞ", voceaba el personaje de Quintanilla en la irrepetible "Plâ”śĂ­cido", la reciente y monumental pelâ”śÂˇcula de Berlanga sobre la hipocresâ”śÂˇa desatada en esos dâ”śÂˇas tan seâ”śâ–’alados de diciembre, en que la ficciâ”śâ”‚n de la justicia social parece conseguirse mediante la distribuciâ”śâ”‚n de unas contadas viandas y bebidas espirituosas, en forma de "aguinaldo", o sentando a un pobre en su mesa, una noche. Escenificaciones como esta de la imagen, donde se acumulan ofrendas votivas, entre ellas un cerdo enjaulado, al trabajador municipal que regula el trâ”śĂ­fico en esa zona de la plaza de Espaâ”śâ–’a, se repetâ”śÂˇan en otros escenarios de la ciudad. Como telâ”śâ”‚n de fondo, el Banco de Espaâ”śâ–’a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65191300, -0.88037400, '0101000020E610000062F54718062CECBF2B6B9BE271D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24730973952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24730973952.webp', 'https://www.flickr.com/photos/zaragozaantigua/24730973952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24042, 'Pl. de Espaâ”śâ–’a 1958', 'Imagen centrada en el tenderete montado por el antropolâ”śâ”‚gico "aguinaldo", o tipismo caracterizado por la donaciâ”śâ”‚n convertida en espectâ”śĂ­culo de viandas y bebidas durante los seâ”śâ–’alados dâ”śÂˇas navideâ”śâ–’os, en este caso en el puesto de trabajo de un municipal guardia de trâ”śĂ­fico sito en la plaza de Espaâ”śâ–’a lindando ya casi con el tramo medio del Coso. Entre las ofrendas destaca sobremanera un joven cerdo enjaulado sobre varios toneles posiblemente de bebidas espirituosas, y con globos decorativos. De fondo escâ”śÂ®nico, la plaza de Espaâ”śâ–’a con su cuadrangular glorieta resultante de la reforma de 1942, como lugar central del trâ”śĂ­nsito de peatones, tranvâ”śÂˇas, autobuses y un pequeâ”śâ–’o carro de transporte a pedales. La plaza contaba entonces con dos zonas de aparcamiento en superficie a ambos lados de la glorieta. Mâ”śĂ­s al fondo, el arranque del paseo de la Indepedencia con su original andador central arbolado, y con vista siquiera borrosa de algunos de los antiguos edificios de tres alturas que conformaban el original paseo, y que pocos aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇan derribados para dar paso a la moderna gran superficie comercial vertical de la Sociedad Espaâ”śâ–’ola de Precios â”śĂśnicos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65213000, -0.88062100, '0101000020E6100000537765170C2EECBFC85EEFFE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30898119208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30898119208.webp', 'https://www.flickr.com/photos/zaragozaantigua/30898119208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24046, 'Plaza de Espaâ”śâ–’a 1940', 'Portada de "Fotos, Semanario Grâ”śĂ­fico de Informaciâ”śâ”‚n y Reportajes", fundado en 1937 como â”śâ”‚rgano propagandâ”śÂˇstico de Falange Espaâ”śâ–’ola de las JONS, para mostrar a los lectores "los magnos acontecimientos de la heroica gesta que vivimos". La imagen ilustra un gran reportaje publicado en este nâ”śâ•‘mero de octubre de 1940, para informar de la extraordinaria confluencia del "XIX Centenario de la Venida de la Virgen del Pilar", la "Fiesta de la Raza", la celebraciâ”śâ”‚n de la victoria militar en la guerra de 1936-39, y la presencia del caudillo Franco. El montaje fotogrâ”śĂ­fico representa el momento en el que el Jefe del Estado parece transitar en su vehâ”śÂˇculo oficial por la plaza de Espaâ”śâ–’a, junto al monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y la Patria, y la fachada del Coso recayente a la plaza, mientras una entregada parroquia de zaragozanos enfundados en trajes folclâ”śâ”‚ricos, sonrâ”śÂˇen felices. El evento fue un clamoroso â”śÂ®xito de crâ”śÂˇtica y pâ”śâ•‘blico. Nadie pudo decir lo contrario. Fuente visual: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31085463495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31085463495.webp', 'https://www.flickr.com/photos/zaragozaantigua/31085463495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24047, 'Pl. de la Constituciâ”śâ”‚n 1931', 'Foto: Miguel Marâ”śÂˇn Chivite. El lunes 13 de abril de 1931, un dâ”śÂˇa despuâ”śÂ®s de las elecciones municipales, se van conociendo datos sobre el triunfo de las candidaturas republicanas, y se forman pequeâ”śâ–’as concentraciones. Es el momento que recoge la imagen, centrada en el monumento a los Mâ”śĂ­rtires de la plaza de la Constituciâ”śâ”‚n, con la Diputaciâ”śâ”‚n Provincial a la izquierda. Al dâ”śÂˇa siguiente serâ”śÂˇa proclamada la Segunda Repâ”śâ•‘blica. Fuente: Heraldo de Aragâ”śâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65207700, -0.88097900, '0101000020E610000020CF2EDFFA30ECBFA5BC564277D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31095726584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31095726584.webp', 'https://www.flickr.com/photos/zaragozaantigua/31095726584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24055, 'Pl. de la Constituciâ”śâ”‚n 1904', 'Aspecto del castillo de madera erigido en la plaza de la Constituciâ”śâ”‚n para las fiestas del Pilar de 1904. A la izquierda, pedestal del monumento a los Mâ”śĂ­rtires, que serâ”śĂ­ colocado e inaugurado a los pocos dâ”śÂˇas. A la derecha, embocadura de la calle de los Mâ”śĂ­rtires. Fuente: cesbor.blogspot.com.es/', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65210100, -0.88098900, '0101000020E61000000458E4D70F31ECBF2E58AA0B78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31586333526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31586333526.webp', 'https://www.flickr.com/photos/zaragozaantigua/31586333526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24891, 'Campus San Francisco 1969', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 29/01/1969. Tras el 18 de julio de 1936, la Universidad fue militarizada y nacionalcatolitizada. La regimental nueva Junta de Gobierno (la anterior fue piqueteada) en octubre de 1936 aprobâ”śâ”‚ la erecciâ”śâ”‚n de un "Monumento a los estudiantes caâ”śÂˇdos por Dios y por Espaâ”śâ–’a", proyectado por Fâ”śÂ®lix Burriel y realizado por Regino Borobio y Josâ”śÂ® Beltrâ”śĂ­n. Se instalâ”śâ”‚ en una zona del nuevo campus de la Plaza de Espaâ”śâ–’a (al poco se cambiarâ”śÂˇa el nombre por el de San Francisco), en la entrada desde la calle Menâ”śÂ®ndez Pelayo. En la imagen, estudiantes universitarios depositando coronas en el monumental monumento, en el aâ”śâ–’o XXX de la Victoria sobre el comunismo. Este monumento fue trasladado por partes en 1981 al patio central del CRM del Ejâ”śÂ®rcito de Tierra, siendo recompuesto sâ”śâ”‚lo en lo referido a las figuras de los soldados centinelas de los laterales.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64262800, -0.89672600, '0101000020E6100000F7216FB9FAB1ECBF38BF61A241D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15081260547.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15081260547.webp', 'https://www.flickr.com/photos/zaragozaantigua/15081260547/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24073, 'Calle de San Miguel 1906', 'Imagen centrada en la portada del itinerante espectâ”śĂ­culo de los "Autâ”śâ”‚matas de Narbâ”śâ”‚n", representado en el espacio esquinero entre la calle de San Miguel y la calle de los Sitios (hacia la derecha), que fue antigua casa de baâ”śâ–’os, y que en 1904 fuera provisional palacio de proyecciones cinematogrâ”śĂ­ficas de los Jimeno. En su lado norte estuvo (1869-1886) el Teatro Lope de Vega, y enfrente, El Prado Aragonâ”śÂ®s/Teatro Goya (1880-1893). A finales de 1906, teniendo de vecino al reciente Cinematâ”śâ”‚grafo Coyne (hacia la izquierda), en este espacio se estableciâ”śâ”‚ el impresionante espectâ”śĂ­culo de los Autâ”śâ”‚matas de Isidro Narbâ”śâ”‚n, que arrancaba con una introducciâ”śâ”‚n en la que se proyectaba una breve pelâ”śÂˇcula cinematogrâ”śĂ­fica que daba paso a la representaciâ”śâ”‚n de un espectâ”śĂ­culo lâ”śÂˇrico a cargo de cerca de 300 marionetas mecanizadas. En el interior del establecimiento se apiâ”śâ–’aban 600 entusiasmados espectadores, las mâ”śĂ­s de las veces niâ”śâ–’as y niâ”śâ–’os. Una de esas niâ”śâ–’as, de 9 aâ”śâ–’os de edad, fue Pilar Bayona Lâ”śâ”‚pez de Ansâ”śâ”‚. En la imagen, capturada desde la calle de San Miguel, un â”śâ”‚rgano monumental que servâ”śÂˇa de ingreso al interior, y cuyas campanillas musicantes atraâ”śÂˇan a la chiquillerâ”śÂˇa de forma tan irresistible como la flauta del cuento a los roedores de Hamelin. Este monumental espectâ”śĂ­culo de Narbâ”śâ”‚n cerrâ”śâ”‚ aâ”śâ–’os despuâ”śÂ®s, y todo su patrimonio artâ”śÂˇstico desapareciâ”śâ”‚ como lâ”śĂ­grimas en la lluvia. En esta misma ubicaciâ”śâ”‚n, entre 1908 y 1913 se estableciâ”śâ”‚ el Cinematâ”śâ”‚grafo Farrusini. Fuente visual: www.mecd.gob.es/.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.65116000, -0.88062100, '0101000020E6100000537765170C2EECBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35561879262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35561879262.webp', 'https://www.flickr.com/photos/zaragozaantigua/35561879262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24846, 'Huelga TUZSA 1986', 'Desde la plaza de Espaâ”śâ–’a, imagen centrada en un grupo de usuarios que asciende a un autobâ”śâ•‘s proveniente de Madrid que sustituyâ”śâ”‚ a los que estaban en huelga de la empresa Transportes Urbanos de Zaragoza S.A., Tuzsa. Llegaron a incorporarse hasta un total de 150 autobuses foranos para hacer los recorridos regulares. Esta movilizaciâ”śâ”‚n se extendiâ”śâ”‚ entre los meses de junio y noviembre y fue liderado por el Colectivo Unitario de Trabajadores, CUT. Las condiciones laborales por las que se regâ”śÂˇa la concesionaria databan de 1961, y el conflicto se prolongâ”śâ”‚ a causa de los sucesivos incumplimientos de lo pactado por parte de la empresa, con infructuosas negociaciones encabezadas por el alcalde Antonio Gonzâ”śĂ­lez Triviâ”śâ–’o y por carpetovetâ”śâ”‚nico gerente de Tuzsa, Luis Senar. El vehâ”śÂˇculo se encuentra en el arranque del Coso Medio. A la izquierda, sede central del Banco Zaragozano. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65211200, -0.88012000, '0101000020E6100000D2C6116BF129ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15296837543.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15296837543.webp', 'https://www.flickr.com/photos/zaragozaantigua/15296837543/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24966, 'Pl. de Espaâ”śâ–’a 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1966. "IV Vuelta Ciclista a Aragâ”śâ”‚n." Imagen de la entrada en la Plaza de Espaâ”śâ–’a desde el Coso Medio, al fondo, en direcciâ”śâ”‚n al Paseo de la Independencia.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65208800, -0.88033300, '0101000020E6100000BEDD921CB02BECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048168268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048168268.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048168268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25058, 'UVE 1989', 'Un agente de la Unidad de Vigilancia Especial de la policâ”śÂˇa local de Zaragoza se dirige a conversar con el fotâ”śâ”‚grafo de Heraldo de Aragâ”śâ”‚n Vicente Jorcano, en la plaza de Espaâ”śâ–’a de Zaragoza. Al fondo, el Banco de Espaâ”śâ–’a. Mâ”śĂ­s informaciâ”śâ”‚n: www.zaragozarebelde.org/uve-elterror-de-la-noche', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65208100, -0.88111100, '0101000020E6100000DAAA24B20F32ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14833840478.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14833840478.webp', 'https://www.flickr.com/photos/zaragozaantigua/14833840478/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25067, 'Santa Engracia y los Innumerables. Siglo IV', 'Santa Engracia y los Innumerables Mâ”śĂ­rtires de Zaragoza. Anâ”śâ”‚nimo, finales del XIX. Basâ”śÂˇlica de Santa Engracia, Zaragoza. Engracia de Zaragoza es un personaje legendario que muere torturado por Diocleciano en el aâ”śâ–’o 303. Las citadas torturas consisten en araâ”śâ–’arle las carnes con garfios, cortarle un pecho y clavarle un clavo en la cabeza, entre otras. Los Innumerables Mâ”śĂ­rtires que vemos detrâ”śĂ­s son 18 personajes legendarios llamados: "Optato, Luperco, Suceso, Marcial, Urbano, Julio, Quintiliano, Publio, Frontonio, Fâ”śÂ®lix, Ceciliano, Evodio, Primitivo, Apodemio, y cuatro mâ”śĂ­s llamados Saturnino. Sobre el nombre de estos â”śâ•‘ltimos hay una doble tradiciâ”śâ”‚n, pues otras fuentes los llaman Casiano, Jenaro, Matutino y Fausto. Con ellos padeciâ”śâ”‚ tambiâ”śÂ®n, aunque sin morir en el tormento, la virgen Engracia de Zaragoza. La Passio los hace morir bajo el prefecto imperial Daciano, el gran perseguidor de los cristianos espaâ”śâ–’oles en tiempo de Diocleciano; despuâ”śÂ®s de ser degollados, sus cuerpos fueron quemados. El cuerpo de Santa Engracia fue sepultado por el obispo Prudencio en una urna de mâ”śĂ­rmol, uniendo a â”śÂ®l las cenizas de sus 18 compaâ”śâ–’eros." Wikipedia A la izquierda de la pintura, la Puerta Cinegia de Zaragoza. Las figuras se encuentran pues en los actuales plaza de Espaâ”śâ–’a y paseo de la Independencia.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.65214200, -0.88072000, '0101000020E61000001EDC9DB5DB2EECBF8C2C996379D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15099020172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15099020172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15099020172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25087, 'Plaza Constituciâ”śâ”‚n 1903', 'Dibujo de Dionisio Lasuâ”śÂ®n. Entrada del rey Alfonso XIII en Zaragoza, en octubre de 1903. Al fondo, la Diputaciâ”śâ”‚n Provincial. Fuente: Heraldo de Aragâ”śâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65211300, -0.88109900, '0101000020E6100000C939B187F631ECBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31707969276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31707969276.webp', 'https://www.flickr.com/photos/zaragozaantigua/31707969276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25096, 'Pl. de la Constituciâ”śâ”‚n 1931', 'Imagen capturada en la terraza del muy reciente cafâ”śÂ®-restaurant Salduba en los bajos del nâ”¬â•‘ 6 de la plaza de la Constituciâ”śâ”‚n, como escenario de un reportaje publicitario protagonizado por la bonaerense actriz y vedete Celia Gâ”śĂ­mez (sentada en primer plano) con ocasiâ”śâ”‚n de su paso por el Teatro Principal. Con diseâ”śâ–’o de los hermanos Borobio, el Salduba se ubicaba donde antes estuvieran el cafâ”śÂ® La Perla, primero, y luego el Casino Artâ”śÂˇstico. Apenas un par de aâ”śâ–’os despuâ”śÂ®s, una ampliaciâ”śâ”‚n de local dio paso a una nueva reforma tambiâ”śÂ®n diseâ”śâ–’ada por los Borobio. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65162500, -0.88062100, '0101000020E6100000537765170C2EECBFC520B07268D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36317808970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36317808970.webp', 'https://www.flickr.com/photos/zaragozaantigua/36317808970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25107, 'Paseo de Santa Engracia nevado 1888', 'Estampa invernal de la plaza de la Constituciâ”śâ”‚n y el arranque del paseo de Santa Engracia. Preside el conjunto la fuente de la Princesa. Fuente visual: La Ilustraciâ”śâ”‚n Espaâ”śâ–’ola y Americana.', 1888, 1888, 1888, 'Siglo XIX', 'CENTRO', 41.65204000, -0.88096500, '0101000020E6100000E275FD82DD30ECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672302348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672302348.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672302348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25112, 'Paseo de Santa Engracia 1890', 'A.M.Z. Sign. 0850. Invierno en el Paseo de Santa Engracia. 1890 Dibujo de F. Pons en el que podemos ver la actual plaza de Espaâ”śâ–’a, presidida por la fuente de la Princesa, desde donde arranca el paseo de Santa Engracia (hoy de la Independencia), proyectado por el gobierno francâ”śÂ®s de la ciudad.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65176400, -0.88117100, '0101000020E61000002FE065868D32ECBFE65AB4006DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878795493.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878795493.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878795493/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25116, 'Plaza de Espaâ”śâ–’a 1978', 'â”¬Ă­Oh! la circulaciâ”śâ”‚n, Josâ”śÂ® Borobio, 1978. Rotuladores de color sobre papel. Vista de la plaza de Espaâ”śâ–’a desde el paseo de la Independencia, en un momento histâ”śâ”‚rico de atasco.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65195000, -0.88101700, '0101000020E6100000810A47904A31ECBF4850FC1873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084818351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084818351.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084818351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25136, 'Los innumerables mâ”śĂ­rtires siglo IV', 'Los innumerables mâ”śĂ­rtires de Zaragoza, aguafuerte de Antonio Banzo, Roma, ca. 1840. El dibujo representa el legendario suceso de martirio de 18 cristianos en el aâ”śâ–’o 303 en Zaragoza. El apelativo de "innumerables" lleva al artista a representarlos en grupo numeroso, saliendo de la Puerta Cinegia para ser eliminados en fila por los malvados romanos en formaciâ”śâ”‚n. Al fondo, mientras, san Lamberto llega con su cabeza en la mano al lugar donde quiere ser enterrado, en la futura ubicaciâ”śâ”‚n del Monasterio de Santa Engracia.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19639506708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19639506708.webp', 'https://www.flickr.com/photos/zaragozaantigua/19639506708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25271, 'Monumento a los Mâ”śĂ­rtires 1902', '"1902, preparaciâ”śâ”‚n del Monumento a los Mâ”śĂ­rtires mientras todavâ”śÂˇa existâ”śÂˇa la fuente de Neptuno. Fuente: Archivo Coyne, AHPZ.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65196900, -0.88092600, '0101000020E61000006B4606B98B30ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894517541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894517541.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894517541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25275, 'Coso e iglesia de San Francisco 1808', 'Fundaciâ”śâ”‚n Lâ”śĂ­zaro Galdiano/IFC. Fernando Brambila, 1808. Lâ”śĂ­piz sobre papel. Dibujo del espacio del Coso que ocuparâ”śĂ­ despuâ”śÂ®s la plaza de San Fernando, actual plaza de Espaâ”śâ–’a. En primer plano, la iglesia del Hospital de Nuestra Seâ”śâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la iglesia de San Francisco. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. Este apunte servirâ”śĂ­ a su autor para realizar la lâ”śĂ­mina "Vista de la calle del Coso" de la serie "Ruinas de Zaragoza".', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14985229539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14985229539.webp', 'https://www.flickr.com/photos/zaragozaantigua/14985229539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25281, 'Plaza de Espaâ”śâ–’a 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 08/04/1968. Fenomenal imagen del fondo escâ”śÂ®nico configurado por el frontal del Coso "pleno", el que se asoma a la Plaza de Espaâ”śâ–’a, mâ”śĂ­s famoso por sus interioridades y tripas en forma de Tubo al que entrar, por ejemplo, por la calle de los Mâ”śĂ­rtires. Los anuncios comerciales incitando al consumo, aun los mâ”śĂ­s cutres, maridaban bastante mejor con el paisaje y el paisanaje que las posmodernas y vacâ”śÂˇas fachadas acristaladas y opacas que dâ”śÂ®cadas despuâ”śÂ®s se impondrâ”śĂ­n como canon postmorten del viejo Tubo. En primer plano, los encapuchados que se llevan siempre la palma.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65195000, -0.88101700, '0101000020E6100000810A47904A31ECBF4850FC1873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15228524762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15228524762.webp', 'https://www.flickr.com/photos/zaragozaantigua/15228524762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25284, 'Plaza de la Constituciâ”śâ”‚n 1900', 'Fuente de Neptuno en la plaza de la Constituciâ”śâ”‚n. 1900. La imagen de Neptuno, realizada durante la etapa de la Administraciâ”śâ”‚n francesa por el alcaâ”śâ–’izano Tomâ”śĂ­s Llovet, segâ”śâ•‘n encargo de Suchet. Al fondo, la fachada del Coso. A la izquierda, un tranvâ”śÂˇa cerrado a tracciâ”śâ”‚n de sangre, de la lâ”śÂˇnea de Circunvalaciâ”śâ”‚n, con vagâ”śâ”‚n tipo "C". Fuente visual: www.bildarchivaustria.at/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65202500, -0.88094800, '0101000020E61000005F402FDCB930ECBF5396218E75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15415780744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15415780744.webp', 'https://www.flickr.com/photos/zaragozaantigua/15415780744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25285, 'Plaza de Espaâ”śâ–’a 1986', 'Plaza de Espaâ”śâ–’a. Tâ”śÂ®cnica mixta sobre lienzo, Eugenio Ampudia, 1986. Fuente: www.aacadigital.com/contenido.php?idarticulo=143', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65211300, -0.88057500, '0101000020E61000003D9B559FAB2DECBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476630780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476630780.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476630780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25288, 'Pl. de Espaâ”śâ–’a 1986', 'Plaza de Espaâ”śâ–’a de Zaragoza. Ignacio Mayayo, lâ”śĂ­piz grafito sobre papel, 1986. En 1989, el Colegio de Aparejadores de Zaragoza realizâ”śâ”‚ una ediciâ”śâ”‚n conmemorativa. Fuente: clubnauticozar.blogspot.com.es/p/cultura-sala-del-rio.html', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15638214911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15638214911.webp', 'https://www.flickr.com/photos/zaragozaantigua/15638214911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
