INSERT INTO public.photos VALUES (25296, 'Coso 1808', '"Vista de la calle del Coso", grabado de la serie "Ruinas de Zaragoza" de Juan Gâ”śĂ­lvez y Fernando Brambila, 1812-1813. Espacio del Coso visto desde la confluencia con la actual calle de Don Jaime. En primer plano, la iglesia del Hospital de Nuestra Seâ”śâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la iglesia del convento de San Francisco, al que tambiâ”śÂ®n corresponde la torre alta de la izquierda. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. A la derecha, ruinas de la Cruz del Coso. Fuente visual: eszaragoza.blogspot.com.es/2014/05/la-crus-del-coso-en-za...', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19083373031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19083373031.webp', 'https://www.flickr.com/photos/zaragozaantigua/19083373031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25302, 'Plaza Constituciâ”śâ”‚n 1902', 'Detalle de la plaza de la Constituciâ”śâ”‚n de Zaragoza en las fiestas de octubre de 1902, con el pie del monumento a los mâ”śĂ­rtires engalanado para la ocasiâ”śâ”‚n, a la espera de que se coloque la estatua, dos aâ”śâ–’os despuâ”śÂ®s. Fuente: www.facebook.com/photo.php?fbid=1458347304491395&set=...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20438461526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20438461526.webp', 'https://www.flickr.com/photos/zaragozaantigua/20438461526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25304, 'Plaza de la Constituciâ”śâ”‚n 1903', 'La plaza de la Constituciâ”śâ”‚n, en el tiempo de espera que se prolongâ”śâ”‚ largarmente desde el desmontaje de la Fuente de la Princesa, y la inauguraciâ”śâ”‚n del Monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y de la Patria, que en la imagen aparece con el pedestal, pero sin nada que soportar. Hasta octubre de 1904, este serâ”śÂˇa el panorama de la plaza, adobado mientras con alguna floreada ocasional. Mientras, la transiciâ”śâ”‚n de los sistemas de tracciâ”śâ”‚n tranviaria permitâ”śÂˇa la ocasional convivencia entre unidades tiradas por mulas, y las nuevas y elâ”śÂ®ctricas, como esta capturada por la Fototipia de Lucas Escolâ”śĂ­. Fuente visual: www.delcampe.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20656248781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20656248781.webp', 'https://www.flickr.com/photos/zaragozaantigua/20656248781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25317, 'Plaza de Espaâ”śâ–’a c.1956', 'Rincâ”śâ”‚n de la plaza de Espaâ”śâ–’a entre el Coso Medio y el paseo de la Independencia, con el velador del Restaurante Nacional. Fuente visual: Foto Casas Torres.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65167000, -0.88084900, '0101000020E610000094DBF63DEA2FECBF65E42CEC69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23239585269.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23239585269.webp', 'https://www.flickr.com/photos/zaragozaantigua/23239585269/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25329, 'Plaza de la Constituciâ”śâ”‚n c.1899', 'Imagen de la plaza de la Constituciâ”śâ”‚n centrada en la Fuente de Neptuno, todavâ”śÂˇa como proveedora del lâ”śÂˇquido elemento. Al fondo, la fachada del Coso, y entrada a la calle de Don Jaime I. Hacia la derecha, continuidad del Coso en su tramo Medio. Aunque la postal sigue llevando la marca de "Laurent", esta imagen no fue realizada por â”śÂ®l, pues Jean Laurent habâ”śÂˇa fallecido en 1892. Pero el mâ”śĂ­s que justificado prestigio de la casa se mantenâ”śÂˇa, aunque el fotâ”śâ”‚grafo fuera otro, en esta breve serie postal de finales del siglo XIX. Fuente visual: www.delcampe.es/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213500, -0.88097700, '0101000020E6100000F3E670ADF630ECBFDAC9E02879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24626981980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24626981980.webp', 'https://www.flickr.com/photos/zaragozaantigua/24626981980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25330, 'Plaza Espaâ”śâ–’a 1983', 'Foto para postal de la plaza de Espaâ”śâ–’a. Fuente: www.delcampe.net', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65208700, -0.88099900, '0101000020E6100000E7E099D02431ECBFC992399677D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25202565469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25202565469.webp', 'https://www.flickr.com/photos/zaragozaantigua/25202565469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25331, 'Gigantes y cabezudos c.1915', 'Comparsa de gigantes y cabezudos en la plaza de la Constituciâ”śâ”‚n hacia 1915. Los gigantes, de izquierda a derecha: el Duque, la Negra, el Chino, la Duquesa y el Rey. Cabezudos que figuran, de izquierda a derecha: Forana, Torero, Berrugâ”śâ”‚n. Al fondo, Gran Hotel Restaurante Europa. Fuente visual: www.ebay.com/', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65208700, -0.88099900, '0101000020E6100000E7E099D02431ECBFC992399677D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25558566986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25558566986.webp', 'https://www.flickr.com/photos/zaragozaantigua/25558566986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25335, 'Plaza de la Constituciâ”śâ”‚n 1899', '"Place de la Constitution", Renâ”śÂ® Ancely, 1899. Plaza de la Constituciâ”śâ”‚n y Fuente de la Princesa, o de Neptuno. En primer plano, un coche cerrado del que comenzara siendo ramal Cuarto tranviario, y ya era denominado lâ”śÂˇnea de "Torrero", de tracciâ”śâ”‚n animal, cuando se estaba pensando en la transiciâ”śâ”‚n pactada hacia la elâ”śÂ®ctrica, aunque tardarâ”śÂˇa tres aâ”śâ–’os en comenzar. Al fondo, emboque del Coso Alto, donde destaca la antigua casa de Juan Coloma, dentro de un irrepetible paâ”śâ–’o de la soleada fachada de ese tramo del Coso, tambiâ”śÂ®n denominado "brasero de los pobres", como literalmente ilustra esta luminosa imagen. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27100961750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27100961750.webp', 'https://www.flickr.com/photos/zaragozaantigua/27100961750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25336, 'Plaza de la Constituciâ”śâ”‚n 1899', '"Place de la Constitution. Fontaine de Neptune", Renâ”śÂ® Ancely, 1899. Imagen de la plaza de la Constituciâ”śâ”‚n centrada en el antiguo paâ”śâ–’o de la fachada del Coso entre los nâ”śâ•‘meros 31 y 37, casi ya en el emboque, a la derecha, de la calle de los Mâ”śĂ­rtires. Focaliza la escena, con luminosidad natural, la funcional Fuente de la Princesa, o de Neptuno, portador de su cetro tridentino. Un carro de aguador, y una seâ”śâ–’ora con câ”śĂ­ntaro, reponen existencias. Tras la fuente, transita un tranvâ”śÂˇa de tracciâ”śâ”‚n animal, posiblemente de la lâ”śÂˇnea de Circunvalaciâ”śâ”‚n. Hace fresco, y el sol de invierno, en un dâ”śÂˇa despejado, sienta bien. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27278686542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27278686542.webp', 'https://www.flickr.com/photos/zaragozaantigua/27278686542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25350, 'Plaza Constituciâ”śâ”‚n 1899', 'Foto: Francisco de Soto. "Acto de colocar la primera piedra del monumento a los Mâ”śĂ­rtires de la religiâ”śâ”‚n y la libertad", octubre de 1899. Serâ”śĂ­ inaugurado cinco aâ”śâ–’os despuâ”śÂ®s, cambiando "libertad" por "patria". Al fondo, la Diputaciâ”śâ”‚n Provincial. Fuente: Revista Iris (Barcelona).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65214800, -0.88106000, '0101000020E6100000520ABABDA431ECBF6E13EE9579D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33156317282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33156317282.webp', 'https://www.flickr.com/photos/zaragozaantigua/33156317282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25352, 'Vista aâ”śÂ®rea plaza Espaâ”śâ–’a c.1968', 'Vista aâ”śÂ®rea centrada en la plaza de Espaâ”śâ–’a. Al fondo, el centro histâ”śâ”‚rico. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65214500, -0.88103400, '0101000020E6100000034015376E31ECBFFD9FC37C79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33541848882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33541848882.webp', 'https://www.flickr.com/photos/zaragozaantigua/33541848882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25357, 'Pl. de la Constituciâ”śâ”‚n 1935', 'Imagen de la reciâ”śÂ®n remodelada fachada del Cafâ”śÂ®-Bar Rojo en su tradicional ubicaciâ”śâ”‚n del nâ”¬â•‘ 5 de la plaza de la Constituciâ”śâ”‚n. Este establecimiento iniciâ”śâ”‚ su andadura en 1915 como Bar Rojo y Blanco, si bien coloquial y abreviadamente ya era conocido como &quot;El Rojo&quot;. En 1935 fue objeto de una intensa reforma, diseâ”śâ–’ada por el arquitecto Fausto Garcâ”śÂˇa Marco, que le confiriâ”śâ”‚ un aspecto modernâ”śÂˇsimo y magnâ”śÂˇfico. Signo de los tiempos, en diciembre de 1936 su nombre fue trocado por el de Cafâ”śÂ® Nacional, a la par que la denominaciâ”śâ”‚n de la plaza transitaba a la fuerza desde la Constituciâ”śâ”‚n a la nueva Espaâ”śâ–’a vieja. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65161700, -0.88087900, '0101000020E61000003E7617282930ECBF4242942F68D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36423504231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36423504231.webp', 'https://www.flickr.com/photos/zaragozaantigua/36423504231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24900, 'Salesianos c.1971', 'El colegio de los Salesianos de Zaragoza se instalâ”śâ”‚ en la Ciudad Jardâ”śÂˇn en el aâ”śâ–’o 1940. En la imagen, vista de sus instalaciones. En primer plano, la avenida de San Juan Bosco (fundador de los Salesianos). A la derecha, la calle de Pedro Lâ”śâ”‚pez de Luna. Fuente visual: www.todocoleccion.net/salesianos-zaragoza-vista-aerea~x43...', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.64447200, -0.90343100, '0101000020E61000009529E620E8E8ECBF0798F90E7ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15518495480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15518495480.webp', 'https://www.flickr.com/photos/zaragozaantigua/15518495480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25362, 'Plaza de Espaâ”śâ–’a 1983', 'Imagen capturada en la plaza de Espaâ”śâ–’a y centrada en el efecto provocado por la visual de dos convexos espejos situados en este frecuentado paso de trâ”śĂ­fico urbano para mejorar la seguridad vial y reducir el riesgo de colisiones. El espejo superior refleja la fachada del Banco de Espaâ”śâ–’a, y el espejo inferior alcanza hasta el inclasificable inmueble del nâ”¬â•‘ 55 del Coso Medio. Al fondo, fachada del Coso recayente a la plaza rematada por los luminosos comerciales de la â”śÂ®poca, y donde se abre el tradicional punto de ingreso al Tubo por la calle de los Mâ”śĂ­rtires. En primer tâ”śÂ®rmino, un autobâ”śâ•‘s urbano.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65213000, -0.88062100, '0101000020E6100000537765170C2EECBFC85EEFFE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48781028063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48781028063.webp', 'https://www.flickr.com/photos/zaragozaantigua/48781028063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25364, 'Plaza de Espaâ”śâ–’a 1955', 'Colorista imagen capturada desde la altura del inmueble del nâ”¬â•‘ 2 de la calle de Don Jaime I, esquinero con el tramo medio del Coso, y centrada en la plaza de Espaâ”śâ–’a con la traza que mantenâ”śÂˇa desde 1942, hasta la radical reforma de 1961. De fondo y de izquierda a derecha, el edificio del Banco Hispano-Americano, la nueva Diputaciâ”śâ”‚n Provincial ya terminada con el râ”śâ”‚tulo de la fachada que la identifica, y el inmueble del nâ”¬â•‘ 1 de la plaza, esquinero con el tramo alto del Coso, todavâ”śÂˇa con su "palomar" sobre el tejado. Entre el movimiento peatonal y el creciente trâ”śĂ­fico rodado, destacan algunas de las tranviaria lâ”śÂˇneas que transitaban desde y por la plaza, como la lâ”śÂˇnea 5. Venecia-Delicias (una composiciâ”śâ”‚n motor+remolque), y la 15. Casablanca (una unidad de la serie 150 o "Topolino").', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65212800, -0.88094400, '0101000020E61000000470B378B130ECBF276728EE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49310316782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49310316782.webp', 'https://www.flickr.com/photos/zaragozaantigua/49310316782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23365, 'Almenara de La Sagrada 1833', '"Almenara de La Sagrada. Tomada desde el Barco por parte del Este mirando al Oeste", litografâ”śÂˇa de Faramundo Blanchard. Esta almenara de desagâ”śâ•ťe se encuentra en Garrapinillos. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19307287348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19307287348.webp', 'https://www.flickr.com/photos/zaragozaantigua/19307287348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25367, 'Plaza de la Constituciâ”śâ”‚n 1900', 'Imagen posiblemente capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 51 del Coso, esquinero con el arranque de la calle de Don Jaime I, orientada hacia la plaza de la Constituciâ”śâ”‚n. El trâ”śĂ­fago urbano incluye el movimiento de peatones, carros, y los coches de punto estacionados al principio del paseo de la Independencia, junto a uno de los urinarios fronteros con la plaza. A la derecha, la Fuente de la Princesa muestra la recurrente estampa de lavanderas y aguadores a los pies de Neptuno.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65208800, -0.88106200, '0101000020E610000080F277EFA831ECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50810577587.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50810577587.webp', 'https://www.flickr.com/photos/zaragozaantigua/50810577587/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25373, 'Plaza de Espaâ”śâ–’a c.1955', 'Imagen capturada desde el arranque del bulevar del paseo de la Independencia y centrada de forma parcial en la cuadrangular y arbolada glorieta central de la plaza de Espaâ”śâ–’a. El monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y la Patria queda fuera de plano y a la izquierda. Hacia el fondo, sombrilla que resguarda levemente a un guardia urbano de la implacable solanera frente al emboque a la calle de los Mâ”śĂ­rtires, flanqueada a la derecha desde 1949 por el bar-cervecerâ”śÂˇa Hergar. En primer tâ”śÂ®rmino y sobre el adoquinado firme, trazado viario por el que el tranvâ”śÂˇa circunvalaba la glorieta', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65207200, -0.88106200, '0101000020E610000080F277EFA831ECBF9351651877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52126528214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52126528214.webp', 'https://www.flickr.com/photos/zaragozaantigua/52126528214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25376, 'Plaza de la Constituciâ”śâ”‚n c. 1929', 'Imagen capturada desde cierta altura en el arranque del tramo medio del Coso, donde a la izquierda y en umbrâ”śÂˇa figura Marâ”śÂˇa Baraibar contemplando la animaciâ”śâ”‚n callejera desde un balcâ”śâ”‚n del hotel de Europa. De fondo escâ”śÂ®nico y por contraste bien luminosa, la plaza de la Constituciâ”śâ”‚n con el ingreso a la calle de los Mâ”śĂ­rtires a la derecha, en cuya esquina destaca el Cafâ”śÂ® Oriental, antecedido por las oficinas del periâ”śâ”‚dico La Voz de Aragâ”śâ”‚n y el Cafâ”śÂ® Royalty. Hacia el fondo continâ”śâ•‘a el soleado tramo alto del Coso que con sus toldos desplegados flanquea el arranque de la calle de Alfonso I. Sobre el firme, armâ”śâ”‚nica convivencia de peatones, carros, vehâ”śÂˇculos a motor de explosiâ”śâ”‚n y un elâ”śÂ®ctrico tranvâ”śÂˇa cerrado, posiblemente en servicio en la lâ”śÂˇnea 7. "Ayuntamiento".', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65179300, -0.88028300, '0101000020E61000004D310741472BECBF8061F9F36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54333738140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54333738140.webp', 'https://www.flickr.com/photos/zaragozaantigua/54333738140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25509, 'Plaza de la Constituciâ”śâ”‚n 1903', 'Imagen de la convivencia del "Arco de la Real Maestranza" y del Pedestal de los "Mâ”śĂ­rtires de la Religiâ”śâ”‚n y la Patria", sin esculturas. El Arco era una temporal composiciâ”śâ”‚n realizada con motivo de una visita a la ciudad del monarca del momento. Detrâ”śĂ­s, el monumento, que acababa de destronar al monarca de los mares, estaba aâ”śâ•‘n sin mâ”śĂ­rtires ni patria. Al fondo, la embocadura con la calle Mâ”śĂ­rtires, antigua Cineja, por el arco del mismo nombre. Fuente visual: Eduardo Laborda, "Zaragoza, la ciudad sumergida", Onagro editores, 2008.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19490467542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19490467542.webp', 'https://www.flickr.com/photos/zaragozaantigua/19490467542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
